('660e8400-e29b-41d4-a716-446655440002', 'Maxfiylik shartnomasi', 
'Ikkala tomon ham shartnoma mavzusi va shartlarini maxfiy saqlashga majbur. Maxfiylikning buzilishi jinoiy javobgarlikka olib kelishi mumkin.', 
'confidentiality', 'medium', 'high', true, 'commercial', 0, 
