ARRAY['nizolash joyini aniq belgilamaslik', 'xarajatlar tengsizligi'], 1),

('660e8400-e29b-41d4-a716-446655440004', 'Kredit shartnomasi', 
'Kredit miqdori, foiz stavkasi va qaytarish tartibi belgilanadi. Kreditni o''z vaqtida qaytarmagani uchun foizlar hisoblanadi.', 
'financial', 'high', 'high', true, 'financial', 0, 
