ARRAY['foiz stavkasi noaniq', 'qaytarish jadvali mavjud emas'], 1),

('660e8400-e29b-41d4-a716-446655440005', 'Ijaraga berish shartnomasi', 
'Ijarachi mulkni to''g''ri foydalanishi va ijaraga to''lovni o''z vaqtida to''lashi kerak. Ijarachi mulkni buzgani uchun javobgarlikni o''z zimmasiga oladi.', 
