INSERT INTO cases (uuid, title, description, case_number, court_name, decision_date, legal_domain, difficulty_level, tags, facts, legal_issues, applicable_laws, decision, reasoning, precedent_value, estimated_time, min_xp_required, xp_reward, status, is_featured, created_at, created_by) VALUES
('770e8400-e29b-41d4-a716-446655440001', 'Toshkent shahar "Bunyodkor" sudi shartnoma nizoli', 
'Ikki kompaniya o''rtasida tuzilgan shartnoma bo''yicha kelishmovchilik. Shartnomaning bajarilmaganligi sababli bir kompaniya sudga murojaat qildi. Sud shartnomaning qonunga muvofiq ekanligini va javobgar tomoni majburiyatlarini bajarishi kerakligini hukm qildi.', 
'2023/452', 'Toshkent shahar "Bunyodkor" tumani sudi', '2023-10-15', 'civil', 'medium', 
ARRAY['shartnoma', 'majburiyat', 'nizol', 'sud'], 
'"A" kompaniyasi "B" kompaniyasi bilan 2023-yil 1-yanvarda 10 million so''m miqdorida qurilish ishlari shartnomasini tuzdi. "A" kompaniyasi shartnomani bajarib, ishlarni tugatdi, ammo "B" kompaniyasi to''lovni to''liq qilmadi. "A" kompaniyasi bir necha bor to''lovni talab qildi, ammo "B" kompaniyasi pul mablag''lari yetarli emasligini da''vo etdi.', 
'1. Shartnoma majburiyatlarini bajarish masalasi. 2. To''lovning o''z vaqtida amalga oshirilmasligi. 3. Shartnomaning buzilishi uchun javobgarlik masalasi.', 
ARRAY['357', '361', '366', '367'], 
'"B" kompaniyasi shartnoma bo''yicha "A" kompaniyasiga 10 million so''m miqdorida qarz 10 million so''m miqdorida to''lovni 30 kun ichida to''lashi, shuningdek, kechikish uchun 2 foiz miqdora jorima to''lashi shart. Sud "B" kompaniyasi shartnoma majburiyatlarini buzgani uchun javobgar tomon ekanligini hukm qildi.', 
'Sud O''zbekiston Respublikasi Fuqarolik kodeksining 361-moddasiga asosan, shartnomaning yozma shaklda tuzilganligini va tomonlar tomonidan imzolanganligini tasdiqladi. Shartnomaning 366-moddasiga ko''ra, majburiyatlarni bajarish majburiyati bor. "B" kompaniyasi majburiyatni bajarmagani uchun 367-moddasiga muvofiq javobgarlikni o''z zimmasiga olishi kerak. Sud shuningdek, 367-moddasiga ko''ra, majburiyatlarni o''z vaqtida bajarilmagani uchun belgilangan jorimani to''lashni buyurdi.', 
'high', 45, 50, 100, 'active', true, '2023-10-15', 1),

('770e8400-e29b-41d4-a716-446655440002', 'Samarqand viloyati "Oqdaryoq" tumani sudi o''g''irlik ishi', 
'Jinoiy ish bo''yicha sud hukmi. Ayolning uyidan qimmatbaho buyumlarni o''g''irlagani uchun sud 3 yilga ozodlikdan mahrum qilish hukmini chiqardi. Ayol o''g''irlangan buyumlarni qaytarib berdi va jabrlanuvchiga tovon to''ladi.', 
'2023/123', 'Samarqand viloyati "Oqdaryoq" tumani sudi', '2023-09-20', 'criminal', 'high', 
ARRAY['o''g''irlik', 'jinoyat', 'sud', 'hukm'], 
'Toshent shahrida yashovchi 35 yoshli ayol 2023-yil 8-avgustda Samarqand viloyatiga qarindoshlariga tashrif buyurdi. U Samarqand shahridagi qarindoshining uyida qolayotgan vaqtida, uy egasi uydan chiqib ketganda, ayol uydan oltin taqincha, 2 ta oltin uzuk va 1 ta oltin sirg''ani olib qochdi. Qimmatbaho buyumlarning umumiy qiymati 50 million so''mni tashkil etdi. Qarindoshi ayolning xatti-harakatini ko''rib, politsiyaga murojaat qildi.', 
'1. O''g''irlik jinoyatining sodir etilishi. 2. Jinoyatning miqyosi. 3. Jabrlanuvchiga yetkazilgan zararni. 4. Ayolning gunohini tan olishi.', 
ARRAY['169', '35', '61'], 
'Ayol o''g''irlik jinoyatini tan oldi va o''g''irlangan barcha buyumlarni qaytarib berdi. Jabrlanuvchi ayoldan kechirim so''radi. Sud ayolning gunohni tan olishini, jabrlanuvchiga yetkazilgan zararni to''lashini va o''g''irlangan buyumlarni qaytarib berishini inobatga olib, O''zbekiston Respublikasi Jinoyat kodeksining 62-moddasiga muvofiq, 3 yilga ozodlikdan mahrum qilish hukmini chiqardi.', 
'Sud O''zbekiston Respublikasi Jinoyat kodeksining 169-moddasiga ko''ra, o''g''irlik - boshqa kishining mulkini o''zlashtirish maqsadida yashirincha olib qochishdir. Ayolning harakatlari 169-moddasining tarkibiy belgilariga to''liq mos keladi. Ayolning gunohni tan olishi va jabrlanuvchiga yetkazilgan zararni to''lashi 62-moddasiga muvofiq yengillashtiruvchi holat sifatida inobatga olindi.', 'medium', 30, 75, 150, 'active', true, '2023-09-20', 1),

('770e8400-e29b-41d4-a716-446655440003', 'Farg''ona viloyati "Beshariq" tumani sudi poroxlanish ishi', 
'Davlat xizmatchisi sifatida ko''rsatib, fuqarolardan pul talab qilgan shaxs sudlanmoqda. Sud shaxsni poroxlanishda aybdor deb topdi va 5 yilga ozodlikdan mahrum qilish hukmini chiqardi.', 
'2023/289', 'Farg''ona viloyati "Beshariq" tumani sudi', '2023-11-05', 'criminal', 'high', 
ARRAY['poroxlanish', 'davlat xizmatchisi', 'porox', 'sud'], 
'Farg''ona viloyati "Beshariq" tumani IIBB 1-bo''limi inspektori 30 yoshli erkak 2023-yil iyun oyidan boshlab o''z vazifasidan foydalanib, fuqarolardan porox talab qila boshladi. U fuqarolarning savdo joylarini tekshirish bahonasida ularning qonunga zid ravishda faoliyat yuritayotganini da''vo qilib, har bir fuqarodan 1 million so''mdan 5 million so''mgacha pul talab qildi. Jami 15 ta fuqarodan 45 million so''m porox olgani aniqlandi.', 
'1. Poroxlanish jinoyatining sodir etilishi. 2. Davlat xizmatchisi sifatida ko''rsatish. 3. Porox miqdori va muddati. 4. Jabrlanuvchilar soni va yetkazilgan zarar.', 
ARRAY['168', '28', '205', '206'], 
'Sud shaxsning poroxlanishda aybdor ekanligini tasdiqladi. U porox olgan pulni qaytarib beradi va jabrlanuvchilarga tovon to''lashi kerak. Sud shaxsning davlat xizmatchisi sifatidagi maqomini bekor qilish hukmini chiqardi.', 
'Sud O''zbekiston Respublikasi Jinoyat kodeksining 168-moddasiga ko''ra, poroxlanish - o''g''irlik yoki talonchilik qilish maqsadida o''zini davlat xizmatchisi yoki xizmat vazifasini bajaruvchi shaxs sifatida ko''rsatishdir. Inspektorning harakatlari 168-moddasining tarkibiy belgilariga to''liq mos keladi. Porox miqdori yirik miqyosda bo''lgani uchun 168-moddasining 3-qismi qo''llanildi.', 'high', 40, 100, 200, 'active', true, '2023-11-05', 1),

('770e8400-e29b-41d4-a716-446655440004', 'Buxoro viloyati "Kogon" tumani sudi tazyiq ishi', 
'Jismoniy azob-uqbatlar qilish orqali shaxsni majbur qilish jinoyati bo''yicha sud hukmi. Ayolni tazyiq qilgan shaxs 7 yilga ozodlikdan mahrum qilindi.', 
'2023/156', 'Buxoro viloyati "Kogon" tumani sudi', '2023-08-10', 'criminal', 'high', 
ARRAY['tazyiq', 'azob-uqbat', 'jismoniy', 'ruhiy'], 
'Buxoro viloyati "Kogon" tumani yashovchi 45 yoshli erkak 2023-yil mart oyidan boshlab o''zining 25 yoshli xotinini tazyiqqa soldi. U xotinini kunduzi va kechasi ishga borishga ruxsat bermadi, uni uyda qamab qo''ydi. Xotinning qochishga urinishlarini pichanlab, uni kaltaklash, qo''llari bilan urib, ochlikdan ochgacha ovqat bermadi. Xotinning qarindoshlari bu holatni politsiyaga xabar berishdi.', 
'1. Tazyiq jinoyatining sodir etilishi. 2. Jismoniy va ruhiy azob-uqbatlar. 3. Shaxsni majbur qilish. 4. Jabrlanuvchining ahvoli.', 
ARRAY['135', '45', '46', '47'], 
'Sud erkakni tazyiq qilishda aybdor deb topdi. U 7 yilga ozodlikdan mahrum qilindi va jabrlanuvchi xotinga 20 million so''m miqdorida tovon to''lashi belgilandi.', 
'Sud O''zbekiston Respublikasi Jinoyat kodeksining 135-moddasiga ko''ra, tazyiq - jismoniy yoki ruhiy azob-uqbatlar qilish orqali shaxsni o''z yoki boshqa shaxslar manfaatini himoya qilish maqsadini amalga oshirishga majbur qilishdir. Erkakning xotiniga nisbatan sodir etgan harakatlari 135-moddasining tarkibiy belgilariga to''liq mos keladi.', 'high', 35, 80, 160, 'active', true, '2023-08-10', 1),

('770e8400-e29b-41d4-a716-446655440005', 'Xorazm viloyati "Xiva" tumani sudi talonchilik ishi', 
